const path = require("path");
const fs = require("fs");

const problemsFile = path.resolve(__dirname, "../../data/problems.json");

let problemsData = null;

function loadProblemsData() {
  if (!problemsData) {
    const raw = fs.readFileSync(problemsFile, "utf8");
    problemsData = JSON.parse(raw);
  }
  return problemsData;
}

/**
 * Get problem by ID.
 * @param {string} problemId
 * @returns {object|null} problem object or null if not found
 */
function getProblemById(problemId) {
  const problems = loadProblemsData();
  return problems.find(p => String(p.id) === String(problemId)) || null;
}

/**
 * Aggregate component statistics for a problem.
 * @param {object} problem
 * @returns {object} aggregated stats with languageCounts, statusCounts, maxPoints
 */
function aggregateComponentStats(problem) {
  if (!problem || !Array.isArray(problem.components)) {
    return {
      languageCounts: {},
      statusCounts: {},
      maxPoints: 0
    };
  }

  const languageCounts = {};
  const statusCounts = {};
  let maxPoints = 0;

  for (const comp of problem.components) {
    // Count languages
    if (comp.language) {
      languageCounts[comp.language] = (languageCounts[comp.language] || 0) + 1;
    }
    // Count statuses
    if (comp.status) {
      statusCounts[comp.status] = (statusCounts[comp.status] || 0) + 1;
    }
    // Track max points
    if (typeof comp.points === "number" && comp.points > maxPoints) {
      maxPoints = comp.points;
    }
  }

  return {
    languageCounts,
    statusCounts,
    maxPoints
  };
}

module.exports = {
  getProblemById,
  aggregateComponentStats
};
