const ProblemsService = require("../services/ProblemsService");

/**
 * GET /api/v1/problems/:problemId
 * Returns problem detail with component statistics or 404 if not found
 */
async function getProblemDetail(req, res) {
  const problemId = req.params.problemId;

  const problem = ProblemsService.getProblemById(problemId);

  if (!problem) {
    return res.status(404).json({
      error: `Problem with id ${problemId} not found.`
    });
  }

  const componentStats = ProblemsService.aggregateComponentStats(problem);

  // Compose response
  const response = {
    ...problem,
    componentStats
  };

  return res.json(response);
}

module.exports = {
  getProblemDetail
};
